SELECT FROM program p INNER JOIN school s ON s.id = p.school_id
AND p.school_id = #{schoolId}
AND s.country_code = #{countryCode}
AND p.subject_category_code = #{subjectCategoryCode}
AND p.direction_code = #{directionCode}
AND ( p.program_name LIKE CONCAT('%', #{keyword}, '%') OR p.college_name LIKE CONCAT('%', #{keyword}, '%') OR s.school_name_cn LIKE CONCAT('%', #{keyword}, '%') OR s.school_name_en LIKE CONCAT('%', #{keyword}, '%') OR s.country_name LIKE CONCAT('%', #{keyword}, '%') OR s.country_code LIKE CONCAT('%', #{keyword}, '%') OR s.city_name LIKE CONCAT('%', #{keyword}, '%') OR p.direction_name LIKE CONCAT('%', #{keyword}, '%') OR p.subject_category_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY s.qs_rank ASC, p.id ASC

SELECT 
FROM program p
INNER JOIN school s ON s.id = p.school_id
WHERE p.school_id = #{schoolId}
ORDER BY p.id ASC
LIMIT #{limit}
